import React from 'react';
import { motion } from 'framer-motion';
import { FaQuoteLeft } from 'react-icons/fa';

const Testimonials = () => {
  const testimonials = [
    {
      quote: "Working with this developer was an absolute pleasure. They delivered beyond our expectations and created a beautiful, responsive website that perfectly represents our brand.",
      author: "John Smith",
      position: "CEO, TechStart Inc.",
      image: "/testimonial1.jpg"
    },
    {
      quote: "Their attention to detail and commitment to quality is outstanding. They not only built our application but also provided valuable insights for improving user experience.",
      author: "Sarah Johnson",
      position: "Product Manager, Digital Solutions",
      image: "/testimonial2.jpg"
    },
    {
      quote: "A true professional who understands both the technical and business aspects of web development. They helped us achieve our goals while staying within budget and timeline.",
      author: "Michael Chen",
      position: "Founder, WebCraft",
      image: "/testimonial3.jpg"
    }
  ];

  return (
    <section id="testimonials" className="section bg-tertiary">
      <div className="container">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2 className="heading">Testimonials</h2>
          <p className="subheading">What others say about me</p>
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {testimonials.map((testimonial, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              className="bg-primary p-6 rounded-lg relative"
            >
              <FaQuoteLeft className="text-4xl text-secondary absolute -top-4 -left-4 opacity-20" />
              <p className="text-textSecondary mb-6 relative z-10">
                "{testimonial.quote}"
              </p>
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-full bg-secondary flex items-center justify-center">
                  <span className="text-primary font-semibold">
                    {testimonial.author.charAt(0)}
                  </span>
                </div>
                <div>
                  <h4 className="font-semibold">{testimonial.author}</h4>
                  <p className="text-sm text-textSecondary">{testimonial.position}</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Testimonials;
